class Solution:
    def flipAndInvertImage(self, image):
        for row in image:
            i, j = 0, len(row) - 1
            while i < j:
                row[i], row[j] = 1 - row[j], 1 - row[i]
                i += 1
                j -= 1
            if i == j:
                row[i] = 1 - row[i]
        return image

