var flipAndInvertImage = function(image) {
    for (const row of image) {
        let i = 0, j = row.length - 1;
        while (i < j) {
            const a = row[i], b = row[j];
            row[i] = 1 - b;
            row[j] = 1 - a;
            i++; j--;
        }
        if (i === j) row[i] = 1 - row[i];
    }
    return image;
};
